'use client';

import { useState } from 'react';
import Image from 'next/image';
import Link from 'next/link';
import { Check } from 'lucide-react';
import ScrollReveal from '@/components/ScrollReveal';
import SectionHeading from '@/components/SectionHeading';
import { SERVICES, PACKAGES } from '@/lib/constants';

export default function ServicesPage() {
  const [activeFilter, setActiveFilter] = useState<string | null>(null);

  const serviceTypes = [...new Set(PACKAGES.map((p) => p.service))];

  const filteredPackages = activeFilter
    ? PACKAGES.filter((p) => p.service === activeFilter)
    : PACKAGES;

  return (
    <>
      {/* ── Hero ── */}
      <section className="bg-bg pt-40 pb-16 px-6">
        <div className="max-w-[980px] mx-auto text-center">
          <p className="text-gold text-[11px] tracking-[0.2em] uppercase font-medium mb-5">
            Services
          </p>
          <h1 className="font-serif text-5xl md:text-7xl text-text-primary leading-[1.08] mb-5">
            What We Offer
          </h1>
          <p className="text-text-secondary text-base md:text-lg leading-relaxed max-w-xl mx-auto">
            From intimate portraits to grand celebrations, every session is crafted
            with intention, artistry, and care.
          </p>
        </div>
      </section>

      {/* ── Services Grid ── */}
      <section className="bg-bg-white py-24 px-6">
        <div className="max-w-[1200px] mx-auto">
          <ScrollReveal>
            <SectionHeading
              subtitle="Our Services"
              title="Photography Services"
              description="Each service is a bespoke experience designed around your unique story."
            />
          </ScrollReveal>

          <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-6">
            {SERVICES.map((service, i) => (
              <ScrollReveal key={service.id} delay={i * 0.08}>
                <div className="card overflow-hidden group">
                  <div className="relative aspect-[3/2] overflow-hidden rounded-t-xl">
                    <Image
                      src={service.image}
                      alt={service.title}
                      fill
                      className="object-cover transition-transform duration-700 group-hover:scale-105"
                      sizes="(max-width: 768px) 100vw, (max-width: 1024px) 50vw, 33vw"
                    />
                  </div>
                  <div className="p-6">
                    <h3 className="font-serif text-xl text-text-primary mb-2">
                      {service.title}
                    </h3>
                    <p className="text-text-secondary text-sm leading-relaxed mb-4">
                      {service.description}
                    </p>
                    <p className="text-gold text-sm font-medium mb-5">
                      Starting at ${service.startingPrice.toLocaleString()}
                    </p>
                    <Link
                      href="/booking"
                      className="btn-primary text-xs px-5 py-2.5"
                    >
                      Book Now
                    </Link>
                  </div>
                </div>
              </ScrollReveal>
            ))}
          </div>
        </div>
      </section>

      {/* ── Pricing Section ── */}
      <section className="bg-bg-light py-24 px-6">
        <div className="max-w-[1200px] mx-auto">
          <ScrollReveal>
            <SectionHeading
              subtitle="Pricing"
              title="Investment Packages"
              description="Transparent pricing for every stage of your journey. Choose the package that fits your vision."
            />
          </ScrollReveal>

          {/* Filter Tabs */}
          <ScrollReveal>
            <div className="flex flex-wrap justify-center gap-3 mb-14">
              <button
                onClick={() => setActiveFilter(null)}
                className={`text-sm px-5 py-2 rounded-full transition-all duration-300 ${
                  activeFilter === null
                    ? 'bg-text-primary text-white'
                    : 'bg-white text-text-secondary border border-border hover:text-text-primary'
                }`}
              >
                All Packages
              </button>
              {serviceTypes.map((type) => (
                <button
                  key={type}
                  onClick={() => setActiveFilter(type)}
                  className={`text-sm px-5 py-2 rounded-full transition-all duration-300 ${
                    activeFilter === type
                      ? 'bg-text-primary text-white'
                      : 'bg-white text-text-secondary border border-border hover:text-text-primary'
                  }`}
                >
                  {type}
                </button>
              ))}
            </div>
          </ScrollReveal>

          <div
            className={`grid grid-cols-1 gap-6 ${
              filteredPackages.length >= 3
                ? 'md:grid-cols-2 lg:grid-cols-3'
                : filteredPackages.length === 2
                  ? 'md:grid-cols-2 max-w-4xl mx-auto'
                  : 'max-w-lg mx-auto'
            }`}
          >
            {filteredPackages.map((pkg, i) => (
              <ScrollReveal key={`${pkg.service}-${pkg.name}`} delay={i * 0.08}>
                <div className="card p-8 relative flex flex-col h-full">
                  {pkg.popular && (
                    <div className="absolute top-4 right-4 bg-gold-bg text-gold text-[10px] font-semibold tracking-[0.12em] uppercase px-3 py-1 rounded-full">
                      Most Popular
                    </div>
                  )}

                  <p className="text-text-tertiary text-sm mb-1">{pkg.service}</p>
                  <h3 className="font-serif text-2xl text-text-primary mb-3">
                    {pkg.name}
                  </h3>
                  <p className="font-serif text-4xl text-gold mb-6">
                    ${pkg.price.toLocaleString()}
                  </p>

                  <ul className="space-y-3 mb-8 flex-1">
                    {pkg.features.map((feature, j) => (
                      <li
                        key={j}
                        className="flex items-start gap-3 text-text-secondary text-sm"
                      >
                        <Check
                          size={15}
                          className="text-gold mt-0.5 flex-shrink-0"
                        />
                        {feature}
                      </li>
                    ))}
                  </ul>

                  <Link
                    href="/booking"
                    className={`btn-primary w-full text-center ${
                      pkg.popular ? '' : ''
                    }`}
                  >
                    Book Now
                  </Link>
                </div>
              </ScrollReveal>
            ))}
          </div>
        </div>
      </section>

      {/* ── CTA ── */}
      <section className="bg-bg-white py-24 px-6 text-center">
        <ScrollReveal>
          <div className="max-w-xl mx-auto">
            <h2 className="font-serif text-3xl md:text-5xl text-text-primary leading-[1.1] mb-5">
              Ready to create something beautiful?
            </h2>
            <p className="text-text-secondary text-base leading-relaxed mb-10">
              Let&apos;s build a custom package tailored to your vision. Every great
              image begins with a conversation.
            </p>
            <Link href="/booking" className="btn-primary px-8 py-4">
              Book Your Session
            </Link>
          </div>
        </ScrollReveal>
      </section>
    </>
  );
}
